// Versión defensiva con limpieza de markdown
const response = $input.first().json;

// Manejar si viene como array o como objeto directo
const data = Array.isArray(response) ? response[0] : response;
const textContent = data?.output?.[0]?.content?.[0]?.text;

if (!textContent) {
  return { 
    has_address: false,
    reason: "No se encontró el contenido de texto",
    addresses: []
  };
}

// Función para limpiar y extraer JSON del texto
function extractJSON(text) {
  let cleaned = text.trim();

  // Remover bloques de código markdown (```json ... ``` o ``` ... ```)
  const codeBlockRegex = /```(?:json)?\s*([\s\S]*?)```/;
  const match = cleaned.match(codeBlockRegex);

  if (match) {
    cleaned = match[1].trim();
  }

  return cleaned;
}

try {
  const cleanedText = extractJSON(textContent);
  const parsed = JSON.parse(cleanedText);

  return {
    has_address: parsed.has_address ?? false,
    reason: parsed.reason ?? "Sin razón especificada",
    addresses: parsed.addresses ?? []
  };
} catch (error) {
  // Si no es JSON válido, retornar valores por defecto
  return {
    has_address: false,
    reason: `No se pudo parsear JSON: ${error.message}`,
    addresses: [],
    raw_content: textContent // Opcional: incluir el contenido original para debug
  };
}

