// Obtener el texto del webhook
const fullText = $('Extract Message Client').first().json.clientReply;

// Función para extraer el mensaje del usuario (antes de la cita del email)
function extractUserMessage(text) {
  if (!text) return '';

  // Patrones comunes de inicio de citas de email en varios idiomas
  const quotePatterns = [
    // Español
    /El\s+\w+,?\s+\d{1,2}\s+\w+\.?\s+\d{4}\s+a\s+la\(?s?\)?\s+\d{1,2}:\d{2}/i,
    /El\s+día\s+\d{1,2}/i,

    // Inglés
    /On\s+\w+,?\s+\w+\s+\d{1,2},?\s+\d{4}\s+at\s+\d{1,2}:\d{2}/i,
    /On\s+\d{1,2}\/\d{1,2}\/\d{2,4}/i,

    // Gmail forwarded
    /---------- Forwarded message/i,
    /---------- Mensaje reenviado/i,

    // Outlook style
    /From:\s*.*\nSent:\s*/i,
    /De:\s*.*\nEnviado:\s*/i,

    // Generic email pattern
    /<[\w.-]+@[\w.-]+>\s*(escribió|wrote|escreveu|a écrit|schrieb):/i,

    // Líneas de separación comunes
    /_{5,}/,
    /-{5,}/
  ];

  let messageEnd = text.length;

  // Buscar el primer patrón que aparezca
  for (const pattern of quotePatterns) {
    const match = text.search(pattern);
    if (match !== -1 && match < messageEnd) {
      messageEnd = match;
    }
  }

  // Extraer y limpiar el mensaje
  let userMessage = text.substring(0, messageEnd).trim();

  // Remover saltos de línea excesivos
  userMessage = userMessage.replace(/\n{3,}/g, '\n\n');

  return userMessage;
}

// Procesar cada item
for (const item of $input.all()) {
  const originalText = item.json.body?.text || fullText;
  item.json.userMessage = extractUserMessage(originalText);
  item.json.originalText = originalText; // Guardar original por si acaso
}

return $input.all();

// Obtener el campo From
const fromField = $input.first().json.From;

// Extraer solo el email usando regex
const emailMatch = fromField.match(/<(.+?)>/);
const email = emailMatch ? emailMatch[1] : fromField;

// Retornar el resultado
return [{
  json: {
    email: email
  }
}];

// Procesar cada item
const results = [];

for (const item of $input.all()) {
  const fullName = $('Search records1').first().json["Full Name"] || item.json.full_name || item.json.fullName || item.json.name || '';

  // Limpiar emojis y caracteres especiales
  let cleaned = fullName
    .replace(/[\u{1F300}-\u{1F9FF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}\u{1F600}-\u{1F64F}\u{1F680}-\u{1F6FF}]/gu, '') // emojis
    .replace(/[★⚡️✨💫🌟⭐️❤️💪🔥✅❌🎯🚀💡🎨📸🎬🎤🎵🎶💃🏃‍♀️🧘‍♀️]/g, '') // emojis comunes
    .replace(/[\u{1D400}-\u{1D7FF}]/gu, '') // letras estilizadas unicode
    .replace(/\|.*$/g, '') // todo después de pipe
    .replace(/@\w+/g, '') // handles de social media
    .replace(/[^a-zA-ZáéíóúÁÉÍÓÚñÑüÜ\s'-]/g, '') // solo letras y espacios
    .replace(/\s+/g, ' ') // múltiples espacios a uno
    .trim();

  const parts = cleaned.split(' ').filter(p => p.length > 1);

  // Validar que tengamos partes válidas (solo letras)
  const validParts = parts.filter(p => /^[a-zA-ZáéíóúÁÉÍÓÚñÑüÜ'-]+$/i.test(p));

  if (validParts.length >= 2) {
    // Caso exitoso - tenemos nombre y apellido
    results.push({
      json: {
        ...item.json,
        original_name: fullName,
        first_name: validParts[0],
        last_name: validParts.slice(1).join(' '),
        confidence: 'high',
        needs_llm: false
      }
    });
  } else if (validParts.length === 1) {
    // Solo un nombre - necesita LLM o marcar como incompleto
    results.push({
      json: {
        ...item.json,
        original_name: fullName,
        first_name: validParts[0],
        last_name: null,
        confidence: 'medium',
        needs_llm: true
      }
    });
  } else {
    // No pudimos extraer nada útil
    results.push({
      json: {
        ...item.json,
        original_name: fullName,
        first_name: null,
        last_name: null,
        confidence: 'low',
        needs_llm: true
      }
    });
  }
}

return results;

