    }
  });
}

return results;

// Leer la dirección del nodo Set Test Data
const fullAddress = $('Set Test Data').first().json.business_address;

if (!fullAddress) {
  return { 
    has_address: false,
    reason: "No se encontró business_address",
    parsed: null
  };
}

// Lista de países comunes (puedes expandir)
const countries = ['USA', 'US', 'United States', 'Canada', 'Mexico', 'UK', 'United Kingdom'];

// Función para detectar y remover país del final
function extractCountry(address) {
  let country = 'USA'; // Default
  let cleanAddress = address.trim();

  for (const c of countries) {
    const regex = new RegExp(',?\\s*' + c + '\\s*$', 'i');
    if (regex.test(cleanAddress)) {
      country = c.toUpperCase() === 'UNITED STATES' ? 'USA' : c.toUpperCase();
      cleanAddress = cleanAddress.replace(regex, '').trim();
      break;
    }
  }

  return { country, cleanAddress };
}

const { country, cleanAddress } = extractCountry(fullAddress);

// Regex para parsear direcciones de EE.UU.
// Formato esperado: "Street Address City, ST ZIP"
const addressRegex = /^(.+?)\s+([A-Za-z\s]+),\s*([A-Z]{2})\s+(\d{5}(?:-\d{4})?)$/;
const match = cleanAddress.match(addressRegex);

if (match) {
  return {
    has_address: true,
    full_address: fullAddress,
    parsed: {
      street: match[1].trim(),
      city: match[2].trim(),
      state: match[3].trim(),
      zip: match[4].trim(),
      country: country
    }
  };
}

// Si no matchea el regex, intentar split por comas
const parts = cleanAddress.split(',').map(p => p.trim());

if (parts.length >= 2) {
  const lastPart = parts[parts.length - 1];
  const stateZipMatch = lastPart.match(/([A-Z]{2})\s+(\d{5}(?:-\d{4})?)/);

  return {
    has_address: true,
    full_address: fullAddress,
    parsed: {
      street: parts[0],
      city: parts.length > 2 ? parts[1] : null,
      state: stateZipMatch ? stateZipMatch[1] : null,
      zip: stateZipMatch ? stateZipMatch[2] : null,
      country: country
    }
  };
}

return {
  has_address: true,
  full_address: fullAddress,
  parsed: null,
  reason: "No se pudo parsear el formato de dirección"
};

const results = [];

for (const item of $input.all()) {
  const html = $('Get Full Email').first().json.html || '';

  // Convertir HTML a texto con saltos de línea
  let text = html
    .replace(/<style[^>]*>.*?<\/style>/gis, '')
    .replace(/<blockquote[^>]*>.*?<\/blockquote>/gis, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<[^>]*>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n /g, '\n')
    .replace(/ \n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  const patterns = [
    /On\s+\w{3},\s+\w{3}\s+\d{1,2},\s+\d{4}\s+at\s+\d{1,2}:\d{2}/i,
    /On\s+\d{1,2}\/\d{1,2}\/\d{2,4}/i,
    /El\s+\d{1,2}\s+de\s+\w+\s+de\s+\d{4}/i,
    /-{3,}\s*Original Message/i,
    /_{3,}\s*From:/i,
    /Sent from my iPhone/i,
    /Get Outlook for/i
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match) {
      text = text.substring(0, match.index).trim();
    }
  }

  results.push({
    json: {
      ...item.json,
      clientReply: text
    }
  });
}

return results;

